    public static List<RekenBedragType> getBedragTypes(Hoedanigheid hoedanigheid, AardKodeExt aard) {
        List<RekenBedragType> result = new ArrayList<>();

        if (aard != null && aard.getCode() == AardKodeExt.I_KODE_EXT.getCode().intValue()) {
            result.add(NETTO);
        } else {
            result.add(BRUTO_MAANDLOON);
            result.addAll(bepaalBedragTypes(hoedanigheid));
        }
        return result;
    }

    private static List<RekenBedragType> bepaalBedragTypes(Hoedanigheid hoedanigheid) {
        switch (hoedanigheid) {
            case MANDATARISSEN:
                return MANDATARIS_BEDRAG_TYPES;
            case WACHTWEDDEN:
                return WACHTWEDDEN_BEDRAG_TYPES;
            case MANDATARISSEN_GEPENSIOENEERD:
            case WERKNEMERS_GEPENSIOENEERD:
                return GEPENSIOENEERD_BEDRAG_TYPES;
            case VASTBENOEMDEN:
                return VASTBENOEMDEN_BEDRAG_TYPES;
            case MANDATARISSEN_NIET_BESCHERMD:
                return MANDATARISSEN_NIET_BESCHERMD_BEDRAG_TYPES;
            case TIJDELIJKEN_EN_CONTRACTUELEN:
                return CONTRACTUEEL_BEDRAG_TYPES;
            case GESUBSIDIEERDE_CONTRACTUELEN:
                return GESCO_BEDRAG_TYPES;
            case STUDENTEN:
                return STUDENT_BEDRAG_TYPES;
            case VRIJWILLIGE_BRANDWEER:
            case DIENST_100_2015_MET_CUMUL_VRIJWILLIGE_BRANDWEER:
            case DIENST_100_2015_ZONDER_CUMUL_VRIJWILLIGE_BRANDWEER:
            case DIENST_100_MET_CUMUL_VRIJWILLIGE_BRANDWEER:
                return VRIJW_BRW_BEDRAG_TYPES;
            case TOEZICHT_BEGELEIDING_BIJLES:
                return TOEZICHT_BEDRAG_TYPES;
            case VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE:
            case ERKENTELIJKHEIDSPREMIE:
                return ERKENTELIJKHEIDSPREMIE_BEDRAG_TYPES;
            case ONTHAALOUDERS:
                return ONTHAALOUDERS_BEDRAG_TYPES;
            case MONITOREN:
            case BEZOLDIGDEN_ZONDER_OVEREENKOMST:
            case VRIJWILLIGERS:
            case RAADSLEDEN:
            case JURYLEDEN:
            case ANDERE:
            case COMMISSIELEDEN:
                return new ArrayList<>();
            default:
                // Schould not go into here until a new Hoedanigheid is added
                return DEFAULT_BEDRAG_TYPES;

        }
    }
